                                        </label>
                                        <input 
                                            type="text" 
                                            id="subject" 
                                            value={formData.subject}
                                            onChange={handleChange}
                                            onFocus={() => handleFocus('subject')}
                                            onBlur={handleBlur}
                                            className="form-input" 
                                            placeholder="What's this about?"
                                            required 
                                        />
                                        <div className="input-highlight"></div>
                                    </div>
                                </div>

